void eraseControls()
{
#if defined(HAVE_M5)
    M5.Display.fillRect(44, 84, 120, 60, TFT_WHITE);
#endif
}

void drawControls(int dpad, int buttons)
{
#if defined(HAVE_M5)    
    int pos[7][2] = {
        {64, 104},
        {64, 84},
        {64, 124},
        {84, 104},
        {44, 104},
        {124, 104},
        {144, 84}
    };

    M5.Display.fillRect(pos[1][0], pos[1][1], 16, 16, (dpad & 1) ? TFT_MAGENTA : TFT_BLACK);
    M5.Display.fillRect(pos[2][0], pos[2][1], 16, 16, (dpad & 2) ? TFT_MAGENTA : TFT_BLACK);
    M5.Display.fillRect(pos[3][0], pos[3][1], 16, 16, (dpad & 4) ? TFT_MAGENTA : TFT_BLACK);
    M5.Display.fillRect(pos[4][0], pos[4][1], 16, 16, (dpad & 8) ? TFT_MAGENTA : TFT_BLACK);
    M5.Display.fillRect(pos[5][0], pos[5][1], 16, 16, (buttons & 1) ? TFT_RED : TFT_BLACK);
    M5.Display.fillRect(pos[6][0], pos[6][1], 16, 16, (buttons & 2) ? TFT_RED : TFT_BLACK);
#endif    
}

void setup() {
    // 1. Core Hardware Init
    M5.begin();           // Necessary for Core 16M hardware stabilization
    initDisplay(); 
    drawImage();
    drawCredit();
    drawTitle();
    drawInstructions();
    
    WiFi.mode(WIFI_OFF); // Disable WiFi to reduce interference with Bluetooth/BLE scanning   

    // 2. Debug Output
    Serial.begin(115200);
    Serial.println("Starting BluePad32 Test...");
    Serial.printf("Free heap before BluePad32 setup: %d bytes\n", ESP.getFreeHeap());

    setup_Bluepad();
}

void loop() {
    M5.update();

    loop_Bluepad();
}
